  ('medical-tech-moex-08738', 'medical-tech', 'medical-tech-moex-106-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '有關糞便肉類纖維鏡檢的敘述，下列何者錯誤？', '["可以協助診斷囊腫纖維變性（cystic fibrosis）", "以methylene blue染色", "檢體應於24小時內檢查完畢", "以高倍視野（400倍）觀察未消化的纖維"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:35+00:00", "source_pdf_sha1": "3ea2b0bc8505", "answer_pdf_sha1": "86541aa18a96", "source_family": "moex-gov-tw", "moex": {"exam_code": "106020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "106", "exam_name": "106年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
