  ('medical-tech-moex-08740', 'medical-tech', 'medical-tech-moex-106-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '有關痰液採集之敘述，下列何者正確？', '["若檢體未能及時送檢，應立即冷凍保存，以提高微生物檢出率", "檢體採集容器可以加入10% glycerin為保存劑，以提高微生物檢出率", "採集時，痰液最好由下呼吸道深部咳出", "支氣管肺泡灌洗液不適用於肺部伺機性感染的檢驗"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:35+00:00", "source_pdf_sha1": "3ea2b0bc8505", "answer_pdf_sha1": "86541aa18a96", "source_family": "moex-gov-tw", "moex": {"exam_code": "106020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "106", "exam_name": "106年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-08741', 'medical-tech', 'medical-tech-moex-106-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下列何者與痰液肺泡巨噬細胞（alveolar macrophages）無關？', '["細胞核緻密、大小不一、通常位於邊緣", "與支氣管上皮細胞聚集後，可見於Creola體（Creola bodies）", "能吞噬碳顆粒，又稱為灰塵細胞（dust cell）", "能吞噬紅血球，會被普魯士藍（Prussian blue）染色"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:35+00:00", "source_pdf_sha1": "3ea2b0bc8505", "answer_pdf_sha1": "86541aa18a96", "source_family": "moex-gov-tw", "moex": {"exam_code": "106020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "106", "exam_name": "106年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-08742', 'medical-tech', 'medical-tech-moex-106-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下列何種細胞不是下呼吸道主要的效應細胞（effector cell）？', '["肺泡巨噬細胞", "嗜酸性白血球", "嗜中性白血球", "淋巴球"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:35+00:00", "source_pdf_sha1": "3ea2b0bc8505", "answer_pdf_sha1": "86541aa18a96", "source_family": "moex-gov-tw", "moex": {"exam_code": "106020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "106", "exam_name": "106年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-08743', 'medical-tech', 'medical-tech-moex-106-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下列何者最易造成腦脊髓液呈xanthochromia？', '["變性白血球", "變性血紅素", "多發性硬化症", "腸病毒"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:35+00:00", "source_pdf_sha1": "3ea2b0bc8505", "answer_pdf_sha1": "86541aa18a96", "source_family": "moex-gov-tw", "moex": {"exam_code": "106020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "106", "exam_name": "106年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-08744', 'medical-tech', 'medical-tech-moex-106-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關於抽取腦脊髓液檢體的敘述，下列何者錯誤？', '["正常的終壓約45～90 mm水柱", "未能及時送檢，生化學檢查的檢體應冷凍保存", "微生物學檢查的檢體應置於冷藏", "成人側躺時壓力為90～180 mm水柱"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:35+00:00", "source_pdf_sha1": "3ea2b0bc8505", "answer_pdf_sha1": "86541aa18a96", "source_family": "moex-gov-tw", "moex": {"exam_code": "106020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "106", "exam_name": "106年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-08745', 'medical-tech', 'medical-tech-moex-106-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關於區分胸膜液（pleural effusion）真性乳糜狀滲出液（chylous effusion）與假性乳糜狀滲出液（pseudochylous effusion） 的敘述，下列何者錯誤？', '["假性乳糜狀滲出液是由於慢性發炎所造成，並非由胸管漏出", "真性乳糜狀滲出液含有高量的膽固醇，濃度可能高於血清含量", "真性乳糜狀滲出液以蘇丹III染色後呈現強陽性，而假性乳糜狀滲出液呈現陰性或弱陽性", "顯微鏡觀察下，真性乳糜狀滲出液主要含有淋巴球，而假性乳糜狀滲出液出現各種細胞"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:35+00:00", "source_pdf_sha1": "3ea2b0bc8505", "answer_pdf_sha1": "86541aa18a96", "source_family": "moex-gov-tw", "moex": {"exam_code": "106020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "106", "exam_name": "106年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-08746', 'medical-tech', 'medical-tech-moex-106-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', 'Rivalta Test為漿液總蛋白質的定性試驗，做法是將一滴漿液檢體滴入裝有下列何者的100 mL純水量筒內，再觀察是否有白色 沈澱物形成的陽性反應？', '["酚", "冰醋酸", "硫酸", "鹽酸"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:35+00:00", "source_pdf_sha1": "3ea2b0bc8505", "answer_pdf_sha1": "86541aa18a96", "source_family": "moex-gov-tw", "moex": {"exam_code": "106020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "106", "exam_name": "106年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-08747', 'medical-tech', 'medical-tech-moex-106-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關於胸膜液酸鹼值之敘述，下列何者錯誤？', '["正常胸膜液之pH值為7.64", "pH值小於6為食道破裂穿孔的特徵", "類風濕性胸膜炎，也會使胸膜液之pH值下降", "可以區分惡性腫瘤與結核病之積水"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:35+00:00", "source_pdf_sha1": "3ea2b0bc8505", "answer_pdf_sha1": "86541aa18a96", "source_family": "moex-gov-tw", "moex": {"exam_code": "106020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "106", "exam_name": "106年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
